comments.body:
```c
#include <x86intrin.h>

__m128i shift64(__m128i v, __m128i s)
{
    s = _mm_and_si128(s, _mm_set1_epi64x(63));
    __m128i x_ = _mm_sll_epi64( v, s );
    __m128i _y = _mm_sll_epi64( v, _mm_srli_si128( s, 8 ) );
    __m128i xy = _mm_castpd_si128( _mm_shuffle_pd( _mm_castsi128_pd( x_ ), _mm_castsi128_pd( _y ), _MM_SHUFFLE2(1,0) ) );
    return xy;
}
```
An example of the failure to peek through bitcasts early enough to simplify `@llvm.x86.sse2.psll.q` calls, resulting in:
```ll
define <2 x i64> @shift64(<2 x i64> %v, <2 x i64> %s) {
entry:
  %and.i = and <2 x i64> %s, splat (i64 63)
  %0 = shufflevector <2 x i64> %and.i, <2 x i64> poison, <2 x i32> zeroinitializer
  %1 = shl <2 x i64> %v, %0
  %2 = shufflevector <2 x i64> %and.i, <2 x i64> poison, <2 x i32> <i32 1, i32 1>
  %3 = shl <2 x i64> %v, %2
  %shufp.uncasted = shufflevector <2 x i64> %1, <2 x i64> %3, <2 x i32> <i32 0, i32 3>
  ret <2 x i64> %shufp.uncasted
}
```
instead of:
```ll
define <2 x i64> @shift64(<2 x i64> %v, <2 x i64> %s) {
entry:
  %and.i = and <2 x i64> %s, splat (i64 63)
  %shl = shl <2 x i64> %v, %and.i
  ret <2 x i64> %shl
}
```
